namespace sv_ac5404d0456748ca86d18ad656ca2d32.Services;

/// <summary>
/// Scoped service that holds the current warehouse selection for a single user circuit.
/// All InteractiveServer components on the same page share one circuit and therefore
/// one instance of this service, giving per-user isolation automatically.
/// </summary>
public sealed class WarehouseState
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId => _currentWarehouseId;

    /// <summary>
    /// Raised after the selected warehouse changes. Subscribers should call
    /// <c>InvokeAsync(StateHasChanged)</c> to re-render on the correct thread.
    /// </summary>
    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }

    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];
}

namespace sv_ac5404d0456748ca86d18ad656ca2d32.Services;

/// <summary>
/// Simulates a database query that returns the number of items below minimum stock level.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }
}

namespace sv_ac5404d0456748ca86d18ad656ca2d32.Services;

/// <summary>
/// Scoped notification hub that broadcasts alert-count changes to every subscriber
/// in the same circuit, regardless of parent-child relationships.
/// </summary>
public sealed class AlertNotificationService
{
    private int _currentAlertCount;

    public int CurrentAlertCount => _currentAlertCount;

    /// <summary>
    /// Raised when the alert count is updated. All subscribed components
    /// (sidebar badge, dashboard card, etc.) receive this event.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public void UpdateAlertCount(int count)
    {
        _currentAlertCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

@rendermode InteractiveServer
@inject WarehouseState State

<div class="px-3 py-2">
    <label class="form-label text-white small mb-1" for="warehouseSelect">
        Current Warehouse
    </label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            value="@State.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var warehouseId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(warehouseId))
        {
            State.SetWarehouse(warehouseId);
        }
    }
}

@rendermode InteractiveServer
@inject AlertNotificationService AlertService
@implements IDisposable

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.CurrentAlertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += HandleAlertCountChanged;
    }

    private void HandleAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= HandleAlertCountChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService InventoryAlertService
@inject AlertNotificationService AlertNotificationService
@implements IAsyncDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4">@GetWarehouseName()</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card @(AlertNotificationService.CurrentAlertCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="card-text fs-1 @(AlertNotificationService.CurrentAlertCount > 0 ? "text-danger" : "text-success")">
                    @AlertNotificationService.CurrentAlertCount
                </p>
                <small class="text-muted">Items below minimum level</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text">
                    @if (_isPolling)
                    {
                        <span class="text-success">● Active</span>
                    }
                    else
                    {
                        <span class="text-muted">○ Inactive</span>
                    }
                </p>
                <small class="text-muted">Refreshes every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

<div class="row mt-4">
    <div class="col-12">
        <div class="card">
            <div class="card-header">
                <h5 class="mb-0">Alert History</h5>
            </div>
            <div class="card-body">
                @if (_alertLog.Count == 0)
                {
                    <p class="text-muted">Waiting for first poll…</p>
                }
                else
                {
                    <table class="table table-sm">
                        <thead>
                            <tr>
                                <th>Time</th>
                                <th>Warehouse</th>
                                <th>Low Stock Items</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var entry in _alertLog.AsEnumerable().Reverse().Take(10))
                            {
                                <tr>
                                    <td>@entry.Timestamp.ToString("HH:mm:ss")</td>
                                    <td>@entry.WarehouseName</td>
                                    <td>
                                        <span class="badge @(entry.Count > 0 ? "bg-danger" : "bg-success")">
                                            @entry.Count
                                        </span>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private readonly List<AlertLogEntry> _alertLog = [];

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertNotificationService.OnAlertCountChanged += HandleAlertCountChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void HandleWarehouseChanged()
    {
        await StopPollingAsync();
        _alertLog.Clear();
        await InvokeAsync(async () =>
        {
            await StartPollingAsync();
        });
    }

    private void HandleAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;
        StateHasChanged();

        // Fire-and-forget the loop; cancellation is handled via the token.
        _ = PollLoopAsync(_cts.Token);
        await Task.CompletedTask;
    }

    private async Task PollLoopAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                var count = await InventoryAlertService.GetLowStockCountAsync(
                    WarehouseState.CurrentWarehouseId);

                // Publish to ALL subscribers (sidebar badge, this page, etc.)
                AlertNotificationService.UpdateAlertCount(count);

                _alertLog.Add(new AlertLogEntry(
                    DateTime.Now,
                    GetWarehouseName(),
                    count));

                await InvokeAsync(StateHasChanged);
                await Task.Delay(TimeSpan.FromSeconds(10), cancellationToken);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            _isPolling = false;
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    private string GetWarehouseName()
    {
        return WarehouseState.AvailableWarehouses
            .FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId).Name
            ?? WarehouseState.CurrentWarehouseId;
    }

    public async ValueTask DisposeAsync()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertNotificationService.OnAlertCountChanged -= HandleAlertCountChanged;
        await StopPollingAsync();
    }

    private sealed record AlertLogEntry(DateTime Timestamp, string WarehouseName, int Count);
}

