@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService InventoryAlertService
@inject AlertNotificationService AlertNotificationService
@implements IAsyncDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4">@GetWarehouseName()</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card @(AlertNotificationService.CurrentAlertCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="card-text fs-1 @(AlertNotificationService.CurrentAlertCount > 0 ? "text-danger" : "text-success")">
                    @AlertNotificationService.CurrentAlertCount
                </p>
                <small class="text-muted">Items below minimum level</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text">
                    @if (_isPolling)
                    {
                        <span class="text-success">● Active</span>
                    }
                    else
                    {
                        <span class="text-muted">○ Inactive</span>
                    }
                </p>
                <small class="text-muted">Refreshes every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

<div class="row mt-4">
    <div class="col-12">
        <div class="card">
            <div class="card-header">
                <h5 class="mb-0">Alert History</h5>
            </div>
            <div class="card-body">
                @if (_alertLog.Count == 0)
                {
                    <p class="text-muted">Waiting for first poll…</p>
                }
                else
                {
                    <table class="table table-sm">
                        <thead>
                            <tr>
                                <th>Time</th>
                                <th>Warehouse</th>
                                <th>Low Stock Items</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var entry in _alertLog.AsEnumerable().Reverse().Take(10))
                            {
                                <tr>
                                    <td>@entry.Timestamp.ToString("HH:mm:ss")</td>
                                    <td>@entry.WarehouseName</td>
                                    <td>
                                        <span class="badge @(entry.Count > 0 ? "bg-danger" : "bg-success")">
                                            @entry.Count
                                        </span>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private readonly List<AlertLogEntry> _alertLog = [];

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertNotificationService.OnAlertCountChanged += HandleAlertCountChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void HandleWarehouseChanged()
    {
        await StopPollingAsync();
        _alertLog.Clear();
        await InvokeAsync(async () =>
        {
            await StartPollingAsync();
        });
    }

    private void HandleAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;
        StateHasChanged();

        // Fire-and-forget the loop; cancellation is handled via the token.
        _ = PollLoopAsync(_cts.Token);
        await Task.CompletedTask;
    }

    private async Task PollLoopAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                var count = await InventoryAlertService.GetLowStockCountAsync(
                    WarehouseState.CurrentWarehouseId);

                // Publish to ALL subscribers (sidebar badge, this page, etc.)
                AlertNotificationService.UpdateAlertCount(count);

                _alertLog.Add(new AlertLogEntry(
                    DateTime.Now,
                    GetWarehouseName(),
                    count));

                await InvokeAsync(StateHasChanged);
                await Task.Delay(TimeSpan.FromSeconds(10), cancellationToken);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            _isPolling = false;
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    private string GetWarehouseName()
    {
        return WarehouseState.AvailableWarehouses
            .FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId).Name
            ?? WarehouseState.CurrentWarehouseId;
    }

    public async ValueTask DisposeAsync()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertNotificationService.OnAlertCountChanged -= HandleAlertCountChanged;
        await StopPollingAsync();
    }

    private sealed record AlertLogEntry(DateTime Timestamp, string WarehouseName, int Count);
}
"}

