namespace sv_ac5404d0456748ca86d18ad656ca2d32.Services;

/// <summary>
/// Scoped service that holds the current warehouse selection for a single user circuit.
/// All InteractiveServer components on the same page share one circuit and therefore
/// one instance of this service, giving per-user isolation automatically.
/// </summary>
public sealed class WarehouseState
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId => _currentWarehouseId;

    /// <summary>
    /// Raised after the selected warehouse changes. Subscribers should call
    /// <c>InvokeAsync(StateHasChanged)</c> to re-render on the correct thread.
    /// </summary>
    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }

    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];
}

