                    DateTime.Now,
                    GetWarehouseName(),
                    count));

                await InvokeAsync(StateHasChanged);
                await Task.Delay(TimeSpan.FromSeconds(10), cancellationToken);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            _isPolling = false;
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

